const express = require('express');
const winston = require('winston');
const fs = require('fs');

// Set up logger
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: './logs/error.log', level: 'error' }),
    new winston.transports.File({ filename: './logs/combined.log' })
  ]
});

const app = express();

app.use(express.json());
app.use(winston.http({ reqProperty: 'request' }));

// Define a middleware to extract and log request data
function logRequest(req, res, next) {
  const username = req.header('username');
  const ipAddress = req.ip;
  const customHeader = req.header('custom-header');

  logger.info({
    message: 'New Request',
    user: username,
    ip_address: ipAddress,
    headers: { ...req.headers }
  });

  next();
}

// Apply middleware to all routes
app.use(logRequest);

// Define a route to handle POST requests to /log-data endpoint
app.post('/log-data', (req, res) => {
  logger.info({
    message: 'New Log Data',
    data: req.body,
    headers: { ...req.headers }
  });

  res.send('Log data received');
});

const port = process.env.PORT || 3000;

// Start the server
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});